    let request_json: serde_json::Value = serde_json::from_str(r#"{"messages":[{"content":"You are a helpful assistant.","role":"system"},{"content":"What is the weather in Paris?","role":"user"},{"content":null,"role":"assistant","tool_calls":[{"function":{"arguments":"{\"location\": \"Paris, France\"}","name":"get_weather"},"id":"call_xyz789","type":"function"}]},{"content":"{\"temperature\": 18, \"unit\": \"celsius\", \"description\": \"Partly cloudy\"}","role":"tool","tool_call_id":"call_xyz789"}],"model":"gpt-4"}"#).unwrap();
    let request = serde_json::from_value(request_json).unwrap();
